/**
 * @file use-resize-observer.ts
 * In-house implementation of the useResizeObserver hook.
 * Adapted from https://usehooks-ts.com/react-hook/use-resize-observer
 */

import { useCallback, useEffect, useRef, useState } from "react";

import type { RefObject } from "react";

/**
 * The size of the observed element.
 *
 * @since 0.15
 */
type Size = {
   width: number | undefined;
   height: number | undefined;
};

/**
 * The options for the ResizeObserver.
 *
 * @since 0.15
 */
type UseResizeObserverOptions<T extends HTMLElement = HTMLElement> = {
   ref: RefObject<T>;
   onResize?: (size: Size) => void;
   box?: "border-box" | "content-box" | "device-pixel-content-box";
};

type BoxSizesKey = keyof Pick<
   ResizeObserverEntry,
   "borderBoxSize" | "contentBoxSize" | "devicePixelContentBoxSize"
>;

function extractSize(
   entry: ResizeObserverEntry,
   box: BoxSizesKey,
   sizeType: keyof ResizeObserverSize,
): number | undefined {
   if (!entry[box]) {
      if (box === "contentBoxSize") {
         return entry.contentRect[sizeType === "inlineSize" ? "width" : "height"];
      }
      return undefined;
   }

   return Array.isArray(entry[box])
      ? entry[box][0][sizeType]
      : // @ts-ignore Support Firefox's non-standard behavior
        (entry[box][sizeType] as number);
}

function useIsMounted(): () => boolean {
   const isMounted = useRef(false);

   useEffect(() => {
      isMounted.current = true;

      return () => {
         isMounted.current = false;
      };
   }, []);

   return useCallback(() => isMounted.current, []);
}

const initialSize: Size = {
   width: undefined,
   height: undefined,
};

/**
 * Custom hook that observes the size of an element using the ResizeObserver API.
 *
 * @see https://developer.mozilla.org/en-US/docs/Web/API/ResizeObserver
 * @since 0.15
 * @hidden
 */
export function useResizeObserver<T extends HTMLElement = HTMLElement>(
   options: UseResizeObserverOptions<T>,
): Size {
   const { ref, box = "content-box" } = options;
   const [{ width, height }, setSize] = useState<Size>(initialSize);
   const isMounted = useIsMounted();
   const previousSize = useRef<Size>({ ...initialSize });
   const onResize = useRef<((size: Size) => void) | undefined>(undefined);
   onResize.current = options.onResize;

   useEffect(() => {
      if (!ref.current) return;

      if (typeof window === "undefined" || !("ResizeObserver" in window)) return;

      const observer = new ResizeObserver(([entry]) => {
         const boxProp =
            box === "border-box"
               ? "borderBoxSize"
               : box === "device-pixel-content-box"
                 ? "devicePixelContentBoxSize"
                 : "contentBoxSize";

         const newWidth = extractSize(entry, boxProp, "inlineSize");
         const newHeight = extractSize(entry, boxProp, "blockSize");

         const hasChanged =
            previousSize.current.width !== newWidth ||
            previousSize.current.height !== newHeight;

         if (hasChanged) {
            const newSize: Size = { width: newWidth, height: newHeight };
            previousSize.current.width = newWidth;
            previousSize.current.height = newHeight;

            if (onResize.current) {
               onResize.current(newSize);
            } else {
               if (isMounted()) {
                  setSize(newSize);
               }
            }
         }
      });

      observer.observe(ref.current, { box });

      return () => {
         observer.disconnect();
      };
   }, [box, ref, isMounted]);

   return { width, height };
}
